const d = $json;
if (!d.session_id || typeof d.session_id !== 'string') { throw new Error('session_id requerido'); }
const UUID_RE = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
if (!UUID_RE.test(d.session_id)) { throw new Error('session_id debe ser UUID valido'); }

// canales: acepta array, string coma-separado, o 'ambos'/'both'
let canales = [];
if (Array.isArray(d.canales)) { canales = d.canales.map(c => String(c).toLowerCase().trim()); }
else if (typeof d.canales === 'string') { const raw = d.canales.toLowerCase().trim(); if (raw === 'ambos' || raw === 'both') canales = ['email', 'whatsapp']; else canales = raw.split(',').map(s => s.trim()).filter(Boolean); }
canales = canales.filter(c => ['email', 'whatsapp'].includes(c));

// parcelas_recomendadas: acepta array o string coma-separado
let parcelas = [];
if (Array.isArray(d.parcelas_recomendadas)) { parcelas = d.parcelas_recomendadas; }
else if (typeof d.parcelas_recomendadas === 'string' && d.parcelas_recomendadas.trim()) { parcelas = d.parcelas_recomendadas.split(',').map(s => s.trim()).filter(Boolean); }
parcelas = parcelas.map(p => String(p).toUpperCase().trim()).filter(Boolean);

// Overrides opcionales: el LLM los envía solo si el lead pidió cambiar el contacto.
const emailOverride = (d.email_override || '').toString().trim();
const waOverrideRaw = (d.whatsapp_override || '').toString().trim();
const waOverrideClean = waOverrideRaw.replace(/[^0-9]/g, '');
const emailValidRe = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
const emailOverrideValid = emailOverride && emailValidRe.test(emailOverride) ? emailOverride : '';
const waOverrideValid = waOverrideClean.length >= 10 ? waOverrideClean : '';

return [{ json: {
  session_id: d.session_id,
  canales,
  parcelas_recomendadas: parcelas,
  forma_pago: (d.forma_pago || '').toString().toLowerCase().trim(),
  presupuesto_o_pie_clp: Number(d.presupuesto_o_pie_clp) || 0,
  uso: (d.uso || '').toString().toLowerCase().trim(),
  plazo_compra: (d.plazo_compra || '').toString().trim().slice(0, 80),
  resumen_conversacion: (d.resumen_conversacion || '').toString().slice(0, 1500),
  email_override: emailOverrideValid,
  whatsapp_override: waOverrideValid,
  send_email: canales.includes('email'),
  send_whatsapp: canales.includes('whatsapp'),
} }];

// Arma los campos para render PDF + HTML de email + caption de WhatsApp.
const input = $('Validate Input').first().json;
const leadArr = $('Fetch Lead').first().json;
const sheetItem = $('Fetch Sheet').first().json;
const uf = $json;

const ufValor = uf && uf.serie && uf.serie[0] && typeof uf.serie[0].valor === 'number' ? uf.serie[0].valor : null;

const lead = Array.isArray(leadArr) ? leadArr[0] : leadArr;
if (!lead || !lead.nombre || !lead.id) {
  return [{ json: {
    ok: false,
    skip: true,
    tool_output_text: 'No encontre tu registro de sesion para enviar el resumen. Confirma tu nombre, email y WhatsApp para continuar.',
  } }];
}
const primerNombre = (lead.nombre || '').split(' ')[0] || 'Cliente';

const csvText = ((sheetItem && (sheetItem.data || sheetItem.body)) || '').toString();
function parseCsv(text) {
  const rows = [];
  let row = []; let field = ''; let inQuotes = false;
  for (let i = 0; i < text.length; i++) {
    const c = text[i];
    if (c === '"') {
      if (inQuotes && text[i + 1] === '"') { field += '"'; i++; }
      else inQuotes = !inQuotes;
    } else if (c === ',' && !inQuotes) { row.push(field); field = ''; }
    else if ((c === '\n' || c === '\r') && !inQuotes) {
      if (c === '\r' && text[i + 1] === '\n') i++;
      row.push(field); rows.push(row); row = []; field = '';
    } else field += c;
  }
  if (field.length || row.length) { row.push(field); rows.push(row); }
  return rows;
}
const pm = (s) => { if (!s) return null; const t = s.toString(); if (t.includes('#')) return null; const n = t.replace(/[^0-9]/g, ''); return n ? parseInt(n, 10) : null; };
const ps = (s) => { if (!s) return null; const n = s.toString().replace(/[^0-9]/g, ''); return n ? parseInt(n, 10) : null; };
const normEstado = (r) => { const e = (r || '').toString().trim().toLowerCase(); if (e.startsWith('disponi')) return 'disponible'; if (e.startsWith('reserv')) return 'reservado'; if (e.startsWith('vendi')) return 'vendido'; return e; };

const rows = parseCsv(csvText);
const byNumero = new Map();
for (const r of rows) {
  if (!r || r.length < 3) continue;
  const lote = (r[1] || '').toString().trim();
  if (!/^(\d{1,3}|B\d{1,2})$/i.test(lote)) continue;
  const cuotaClp = pm(r[11]);
  byNumero.set(lote.toUpperCase(), {
    numero: lote.toUpperCase(),
    destacada: ((r[0] || '').toString().trim() === '⭐'),
    estado: normEstado(r[2]),
    tamano_m2: ps(r[3]),
    precio_contado: pm(r[6]),
    descuento_pct: ps(r[7]),
    precio_credito: pm(r[9]),
    pie_minimo_50pct: pm(r[10]),
    cuota_mensual_clp: cuotaClp,
    cuota_mensual_uf: cuotaClp && ufValor ? Math.round((cuotaClp / ufValor) * 100) / 100 : null,
  });
}

const parcelas = input.parcelas_recomendadas
  .map(n => byNumero.get(n.toUpperCase()))
  .filter(Boolean);

const BASE_URL = 'https://mirador-villarrica-chatbot.vercel.app';

const pdfData = {
  primerNombre,
  uso: input.uso || '',
  forma_pago: input.forma_pago || '',
  plazo_compra: input.plazo_compra || '',
  resumen_conversacion: (input.resumen_conversacion || '').trim(),
  parcelas: parcelas.map(p => ({
    numero: p.numero,
    destacada: !!p.destacada,
    estado: p.estado,
    tamano_m2: p.tamano_m2,
    precio_contado: p.precio_contado,
    descuento_pct: p.descuento_pct,
    precio_credito: p.precio_credito,
    pie_minimo_50pct: p.pie_minimo_50pct,
    cuota_mensual_clp: p.cuota_mensual_clp,
    cuota_mensual_uf: p.cuota_mensual_uf,
  })),
  base_url: BASE_URL,
};

const emailSubject = 'Tu resumen personalizado · Mirador de Villarrica';

const emailBody = ''
  + '<div style="font-family:Arial,Helvetica,sans-serif;font-size:14px;line-height:1.65;color:#333;max-width:560px;padding:16px;">'
  +   `<p style="margin:0 0 14px;">Hola <strong>${primerNombre}</strong>,</p>`
  +   '<p style="margin:0 0 14px;">Te adjunto el PDF con el resumen personalizado de lo que conversamos: las parcelas recomendadas con precios al contado y a crédito directo, el detalle según tu caso y los enlaces útiles del proyecto.</p>'
  +   '<p style="margin:0 0 14px;">Si tienes más dudas no dudes en preguntarme por acá y con gusto te ayudo. Si ya estás decidido y quieres pasar al proceso de reserva y/o compra, dímelo y te comunico con nuestro equipo de ventas para coordinar una llamada.</p>'
  +   '<p style="margin:18px 0 10px;color:#1a3d2e;font-weight:bold;">¡Un saludo!</p>'
  +   '<table role="presentation" cellpadding="0" cellspacing="0" border="0" width="100%" style="margin-top:18px;border-collapse:collapse;border-radius:8px;overflow:hidden;">'
  +     '<tr>'
  +       `<td align="center" bgcolor="#1a3d2e" style="background-color:#1a3d2e;padding:16px 20px 12px;">`
  +         '<table role="presentation" cellpadding="0" cellspacing="0" border="0">'
  +           '<tr>'
  +             `<td style="vertical-align:middle;padding:0 18px 0 0;"><img src="${BASE_URL}/assets/mirador-logo.png" width="88" alt="Mirador de Villarrica" style="display:block;max-width:88px;height:auto;border:0;"/></td>`
  +             '<td style="vertical-align:middle;padding:0 14px;color:#ffffff;font-size:10px;letter-spacing:2px;text-transform:uppercase;font-family:Arial,sans-serif;white-space:nowrap;">Un proyecto de</td>'
  +             `<td style="vertical-align:middle;padding:0 0 0 18px;"><img src="${BASE_URL}/assets/terra-segura-logo.png" width="104" alt="Terra Segura" style="display:block;max-width:104px;height:auto;border:0;"/></td>`
  +           '</tr>'
  +         '</table>'
  +       '</td>'
  +     '</tr>'
  +     '<tr>'
  +       '<td align="center" bgcolor="#1a3d2e" style="background-color:#1a3d2e;padding:0 20px 16px;">'
  +         '<div style="height:1px;background:#ffffff22;margin-bottom:12px;line-height:1px;font-size:0;">&nbsp;</div>'
  +         '<p style="margin:0 0 4px;font-family:Arial,Helvetica,sans-serif;font-size:12.5px;font-weight:bold;color:#ffffff;">Equipo de Ventas — Terra Segura Inmobiliaria</p>'
  +         '<p style="margin:0 0 8px;font-family:Arial,Helvetica,sans-serif;font-size:11.5px;color:#c5d5cc;">Mirador de Villarrica · Región de La Araucanía</p>'
  +         '<p style="margin:0;font-family:Arial,Helvetica,sans-serif;font-size:11.5px;color:#ffffff;">'
  +           '<a href="https://wa.me/56940329987" style="color:#ffffff;text-decoration:none;"><span style="color:#25D366;">●</span> WhatsApp +56 9 4032 9987</a>'
  +           '&nbsp;·&nbsp;'
  +           '<a href="mailto:diego@terrasegura.cl" style="color:#ffffff;text-decoration:none;">diego@terrasegura.cl</a>'
  +         '</p>'
  +       '</td>'
  +     '</tr>'
  +   '</table>'
  + '</div>';

const whatsappCaption = ''
  + `Hola ${primerNombre},\n\n`
  + `Te adjunto el PDF con el resumen personalizado de lo que conversamos: las parcelas recomendadas con precios al contado y a crédito directo, el detalle según tu caso y los enlaces útiles del proyecto.\n\n`
  + `Si tienes más dudas no dudes en preguntarme por acá y con gusto te ayudo. Si ya estás decidido y quieres pasar al proceso de reserva y/o compra, dímelo y te comunico con nuestro equipo de ventas para coordinar una llamada.\n\n`
  + `*Equipo Terra Segura*\n`
  + `_Mirador de Villarrica · Región de La Araucanía_`;

const emailDestino = input.email_override || lead.email || '';
const waRaw = input.whatsapp_override || lead.whatsapp || '';
let phoneClean = waRaw.toString().replace(/[^0-9]/g, '');
if (phoneClean.startsWith('9') && phoneClean.length === 9) phoneClean = '56' + phoneClean;

const canValidEmail = input.send_email && emailDestino && /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(emailDestino);
const canValidWa = input.send_whatsapp && phoneClean.length >= 10;

return [{ json: {
  ok: true,
  skip: false,
  session_id: input.session_id,
  lead_id: lead.id,
  nombre: lead.nombre,
  primerNombre,
  email: emailDestino,
  email_source: input.email_override ? 'override' : 'form',
  phone_clean: phoneClean,
  whatsapp_source: input.whatsapp_override ? 'override' : 'form',
  can_email: canValidEmail,
  can_whatsapp: canValidWa,
  emailSubject,
  emailBody,
  whatsappCaption,
  pdfData,
  parcelas_ok: parcelas.length,
  canales_input: input.canales,
  score_history: Array.isArray(lead.score_history) ? lead.score_history : [],
} }];

const built = $('Build Messages').first().json;
const primerNombre = built.primerNombre || 'hola';

const sent = [];
const failed = [];
let waError = null;
let waNumber = built.phone_clean || '';

if (built.can_email) {
  sent.push('email');
}

if (built.can_whatsapp) {
  let waResp = null;
  try { waResp = $('Evolution Send WA').first().json; } catch (e) { waResp = null; }
  const statusCode = waResp && typeof waResp.status === 'number' ? waResp.status : null;
  const respBody = waResp ? (waResp.response || waResp) : null;
  const message = respBody && respBody.message;
  const notRegistered = Array.isArray(message) && message.some(m => m && m.exists === false);
  if (notRegistered) { failed.push('whatsapp'); waError = 'number_not_registered'; }
  else if (statusCode && statusCode >= 400) { failed.push('whatsapp'); waError = 'api_error'; }
  else if (waResp && (waResp.key || waResp.message || waResp.status === 'PENDING' || statusCode === null)) { sent.push('whatsapp'); }
  else { failed.push('whatsapp'); waError = 'unknown'; }
}

const prettyNumber = waNumber ? `+${waNumber}` : 'tu WhatsApp';
let tool_output_text;

if (sent.length > 0 && failed.length === 0) {
  const canal = sent.length === 2 ? 'correo y WhatsApp' : sent[0] === 'email' ? 'correo' : 'WhatsApp';
  tool_output_text = `Listo ${primerNombre}, ya tienes el resumen en tu ${canal} 📨 Revisalo con calma y cualquier duda me la cuentas por aca. ¿Hay algo mas que quieras consultarme o prefieres que te conecte con nuestro equipo de ventas para coordinar una llamada y avanzar con la compra?`;
} else if (sent.length > 0 && waError === 'number_not_registered') {
  tool_output_text = `El resumen ya te llego al correo ${primerNombre}. Pero el numero ${prettyNumber} no parece estar registrado en WhatsApp. ¿Me confirmas el numero correcto y lo reintento? O si prefieres, te conecto con nuestro equipo de ventas directamente.`;
} else if (sent.length > 0 && failed.includes('whatsapp')) {
  tool_output_text = `Te llego por correo ${primerNombre}, pero el envio por WhatsApp fallo por un tema tecnico. ¿Quieres que lo reintente o prefieres que derive tu caso al equipo para que te contacten directo?`;
} else if (failed.length > 0 && waError === 'number_not_registered') {
  tool_output_text = `El numero ${prettyNumber} no esta registrado en WhatsApp ${primerNombre}. ¿Me confirmas el numero correcto? Lo reintento en cuanto me digas, o si prefieres te conecto con el equipo de ventas directamente.`;
} else if (failed.length > 0) {
  tool_output_text = `No logre enviar el resumen ${primerNombre}, quedo un tema tecnico pendiente. Dejame pasar tu caso al equipo de ventas para que te contacten de inmediato.`;
} else {
  tool_output_text = `No pude preparar el envio ${primerNombre}. Confirmame tu correo y WhatsApp y lo intento de nuevo.`;
}

return [{ json: {
  ok: sent.length > 0,
  lead_id: built.lead_id,
  canales_enviados: sent,
  canales_fallidos: failed,
  wa_error: waError,
  tool_output_text,
} }];

const buf = await this.helpers.getBinaryDataBuffer(0, 'data');
$input.item.json.pdfBase64 = buf.toString('base64');
return $input.item;
